import { describe, expect, test } from 'bun:test';
import { buildProtocol69ProjectionEnvelope } from './protocol69';
import {
  buildR1FoilWitnessReport,
  r1FoilReportToChannelWitness,
  validateR1FoilWitnessReport,
} from './protocol69-r1-witness';

describe('protocol69 R1 FOIL witness', () => {
  test('builds a canonical BTLE witness report with protocol69 projection', () => {
    const report = buildR1FoilWitnessReport({
      deviceId: ' r1-alpha ',
      channelId: 37,
      rssiDbm: -42,
      packetSeen: true,
      cadenceMs: 250,
      timestampMs: 1_775_000_000_000,
    });

    expect(report.deviceId).toBe('r1-alpha');
    expect(report.ingress).toBe('BluetoothChannelWitness');
    expect(report.projection.protocol).toBe('protocol69');
    expect(report.projection.wordName).toBe('sixty9');
    expect(report.projection.broadcastSymbol).toBe(66);
    expect(report.projection.localFoilOperand).toBe(7);
    expect(report.projection.expectedProjection).toBe(69);
  });

  test('validates reports and maps them to FOIL channel witnesses', () => {
    const report = validateR1FoilWitnessReport(
      buildR1FoilWitnessReport({
        deviceId: 'did:aeon:device:r1',
        channelId: 38,
        rssiDbm: -50,
        packetSeen: true,
        timestampMs: 1,
        projection: buildProtocol69ProjectionEnvelope(),
      })
    );

    expect(r1FoilReportToChannelWitness(report)).toEqual({
      ingress: 'BluetoothChannelWitness',
      channelId: 38,
      frequencyHz: null,
      rssiDbm: -50,
      packetSeen: true,
    });
  });

  test('rejects protocol69 projection drift', () => {
    const projection = {
      ...buildProtocol69ProjectionEnvelope(),
      expectedProjection: 68,
    };

    expect(() =>
      validateR1FoilWitnessReport({
        ...buildR1FoilWitnessReport({
          deviceId: 'r1-alpha',
          channelId: 39,
          rssiDbm: -35,
          packetSeen: true,
          timestampMs: 1,
        }),
        projection,
      })
    ).toThrow(/projection/);
  });

  test('rejects malformed BTLE witness fields', () => {
    expect(() =>
      buildR1FoilWitnessReport({
        deviceId: '',
        channelId: 70_000,
        rssiDbm: -200,
        packetSeen: true,
        timestampMs: -1,
      })
    ).toThrow();
  });
});
